const input = $json.body ?? $json;
const required = ['text', 'project_id'];
for (const key of required) {
  const value = input[key];
  if (value === undefined || value === null || String(value).trim() === '') {
    throw new Error(`Missing required field: ${key}`);
  }
}

const normalizeNullable = (value) => {
  if (value === undefined || value === null) return null;
  const normalized = String(value).trim();
  return normalized === '' ? null : normalized;
};

const tags = Array.isArray(input.tags)
  ? input.tags.map((tag) => String(tag).trim()).filter((tag) => tag !== '')
  : [];

const parsedLimit = Number(input.limit ?? 5);
const limit = Number.isFinite(parsedLimit) ? Math.max(1, Math.min(20, Math.trunc(parsedLimit))) : 5;

const normalized = {
  text: String(input.text).trim(),
  project_id: String(input.project_id).trim(),
  sequence_id: normalizeNullable(input.sequence_id),
  scene_id: normalizeNullable(input.scene_id),
  shot_id: normalizeNullable(input.shot_id),
  entity_type: normalizeNullable(input.entity_type),
  tags,
  source: normalizeNullable(input.source),
  limit
};

return [{
  json: {
    normalized,
    embed_request: {
      text: normalized.text,
      metadata: {
        project_id: normalized.project_id,
        sequence_id: normalized.sequence_id,
        scene_id: normalized.scene_id,
        shot_id: normalized.shot_id,
        entity_type: normalized.entity_type,
        source: normalized.source,
        limit: normalized.limit
      }
    }
  }
}];

const normalized = $('Normalize Search Request').first().json.normalized;
const embedding = $json;

if (!Array.isArray(embedding.vector) || embedding.vector.length !== 384) {
  throw new Error(`Invalid embedding dimensions: ${embedding.dimensions}`);
}

const must = [
  { key: 'project_id', match: { value: normalized.project_id } }
];

if (normalized.sequence_id) {
  must.push({ key: 'sequence_id', match: { value: normalized.sequence_id } });
}
if (normalized.scene_id) {
  must.push({ key: 'scene_id', match: { value: normalized.scene_id } });
}
if (normalized.shot_id) {
  must.push({ key: 'shot_id', match: { value: normalized.shot_id } });
}
if (normalized.entity_type) {
  must.push({ key: 'entity_type', match: { value: normalized.entity_type } });
}
if (normalized.source) {
  must.push({ key: 'source', match: { value: normalized.source } });
}
if (Array.isArray(normalized.tags) && normalized.tags.length > 0) {
  must.push({ key: 'tags', match: { any: normalized.tags } });
}

return [{
  json: {
    search_request: {
      vector: embedding.vector,
      limit: normalized.limit,
      with_payload: true,
      with_vector: false,
      filter: { must }
    },
    search_meta: {
      query: normalized,
      embedding_model: embedding.model,
      dimensions: embedding.dimensions
    }
  }
}];

const meta = $('Build Search Request').first().json.search_meta;
const raw = Array.isArray($json.result) ? $json.result : [];
const results = raw.map((item) => {
  const payload = item.payload ?? {};
  return {
    point_id: item.id ?? null,
    score: item.score ?? null,
    project_id: payload.project_id ?? null,
    sequence_id: payload.sequence_id ?? null,
    scene_id: payload.scene_id ?? null,
    shot_id: payload.shot_id ?? null,
    entity_type: payload.entity_type ?? null,
    title: payload.title ?? null,
    content: payload.content ?? null,
    tags: Array.isArray(payload.tags) ? payload.tags : [],
    source: payload.source ?? null,
    created_at: payload.created_at ?? null
  };
});

return [{
  json: {
    ok: true,
    collection: 'cine_project_context',
    embedding_model: meta.embedding_model,
    dimensions: meta.dimensions,
    query: meta.query,
    count: results.length,
    results
  }
}];
